// FieldConfiguration is the resolver for the fieldConfiguration field.
func (r *queryResolver) FieldConfiguration(ctx context.Context, workspaceID string) (*graphql1.FieldConfiguration, error) {
	schema := r.UseCases.Case.GetFieldConfiguration(workspaceID)

	fields := make([]*graphql1.FieldDefinition, len(schema.Fields))
	for i, field := range schema.Fields {
		options := make([]*graphql1.FieldOption, len(field.Options))
		for j, opt := range field.Options {
			metadata := opt.Metadata
			if metadata == nil {
				metadata = make(map[string]any)
			}
			metadataJSON, _ := json.Marshal(metadata)
			metadataStr := string(metadataJSON)

			options[j] = &graphql1.FieldOption{
				ID:          opt.ID,
				Name:        opt.Name,
				Description: &field.Options[j].Description,
				Metadata:    &metadataStr,
			}
		}

		fieldType := toGraphQLFieldType(field.Type)

		fields[i] = &graphql1.FieldDefinition{
			ID:          field.ID,
			Name:        field.Name,
			Type:        fieldType,
			Required:    field.Required,
			Description: &field.Description,
			Options:     options,
		}
	}

	statusSet := r.UseCases.Case.GetActionStatusSet(workspaceID)

	return &graphql1.FieldConfiguration{
		Fields: fields,
		Labels: &graphql1.EntityLabels{
			Case: schema.Labels.Case,
		},
		ActionConfig: toActionConfig(statusSet),
	}, nil
}

// CaseStatusConfig is the resolver for the caseStatusConfig field.
func (r *queryResolver) CaseStatusConfig(ctx context.Context, workspaceID string) (*graphql1.ActionConfig, error) {
	statusSet := r.UseCases.Case.GetCaseStatusSet(workspaceID)
	if statusSet == nil {
		// Channel-mode workspace: no Case status set. Null is the schema
		// contract for "this workspace does not use Case-level statuses".
		return nil, nil
	}
	return toActionConfig(statusSet), nil
}

