// ValidateGitHubRepo is the resolver for the validateGitHubRepo field.
func (r *queryResolver) ValidateGitHubRepo(ctx context.Context, workspaceID string, repository string) (*graphql1.GitHubRepoValidationResult, error) {
	result, err := r.UseCases.Source.ValidateGitHubRepo(ctx, repository)
	if err != nil {
		return nil, err
	}

	gql := &graphql1.GitHubRepoValidationResult{
		Valid:                result.Valid,
		CanFetchPullRequests: result.CanFetchPullRequests,
		CanFetchIssues:       result.CanFetchIssues,
	}
	if result.Owner != "" {
		gql.Owner = &result.Owner
	}
	if result.Repo != "" {
		gql.Repo = &result.Repo
	}
	if result.FullName != "" {
		gql.FullName = &result.FullName
	}
	if result.Description != "" {
		gql.Description = &result.Description
	}
	if result.IsPrivate {
		gql.IsPrivate = &result.IsPrivate
	}
	if result.PullRequestCount > 0 {
		gql.PullRequestCount = &result.PullRequestCount
	}
	if result.IssueCount > 0 {
		gql.IssueCount = &result.IssueCount
	}
	if result.ErrorMessage != "" {
		gql.ErrorMessage = &result.ErrorMessage
	}

	return gql, nil
}

// AssistLogs is the resolver for the assistLogs field.
func (r *queryResolver) AssistLogs(ctx context.Context, workspaceID string, caseID int, limit *int, offset *int) (*graphql1.AssistLogConnection, error) {
	// Access control: check parent case
	parentCase, caseErr := r.repo.Case().Get(ctx, workspaceID, int64(caseID))
	if caseErr == nil {
		token, tokenErr := auth.TokenFromContext(ctx)
		if tokenErr == nil && !model.IsCaseAccessible(parentCase, token.Sub) {
			return &graphql1.AssistLogConnection{
				Items:      []*graphql1.AssistLog{},
				TotalCount: 0,
				HasMore:    false,
			}, nil
		}
	}

	limitVal := 20
	if limit != nil && *limit > 0 {
		limitVal = *limit
	}
	if limitVal > 50 {
		limitVal = 50
	}

	offsetVal := 0
	if offset != nil && *offset > 0 {
		offsetVal = *offset
	}

	logs, totalCount, err := r.repo.AssistLog().List(ctx, workspaceID, int64(caseID), limitVal, offsetVal)
	if err != nil {
		return nil, err
	}

	items := make([]*graphql1.AssistLog, len(logs))
	for i, l := range logs {
		items[i] = &graphql1.AssistLog{
			ID:        string(l.ID),
			CaseID:    int(l.CaseID),
			Summary:   l.Summary,
			Actions:   l.Actions,
			Reasoning: l.Reasoning,
			NextSteps: l.NextSteps,
			CreatedAt: l.CreatedAt,
		}
	}

	hasMore := (offsetVal + len(logs)) < totalCount

	return &graphql1.AssistLogConnection{
		Items:      items,
		TotalCount: totalCount,
		HasMore:    hasMore,
	}, nil
}

// CaseJobRunLogs is the resolver for the caseJobRunLogs field.
func (r *queryResolver) CaseJobRunLogs(ctx context.Context, workspaceID string, caseID int, first *int, after *string) (*graphql1.JobRunLogConnection, error) {
	page := 0
	if first != nil {
		page = *first
	}
	result, err := r.UseCases.JobRun.ListLogsByCase(ctx, workspaceID, int64(caseID), page, after)
	if err != nil {
		return nil, err
	}
	items := make([]*graphql1.JobRunLog, 0, len(result.Items))
	for _, log := range result.Items {
		items = append(items, toGraphQLJobRunLog(log, r.UseCases.JobRun.ResolveJobName(workspaceID, log.JobID)))
	}
	return &graphql1.JobRunLogConnection{
		Items:      items,
		NextCursor: result.NextCursor,
	}, nil
}

